const ALLOWED_ORIGINS = ['https://example.com', 'https://app.example.com'];
const RATE_LIMIT_WINDOW_MS = 60000;
const RATE_LIMIT_MAX_REQUESTS = 100;

const rateLimitMap = new Map();

function checkRateLimit(clientIP) {
  const now = Date.now();
  const record = rateLimitMap.get(clientIP);

  if (!record) {
    rateLimitMap.set(clientIP, { count: 1, windowStart: now });
    return true;
  }

  if (now - record.windowStart > RATE_LIMIT_WINDOW_MS) {
    rateLimitMap.set(clientIP, { count: 1, windowStart: now });
    return true;
  }

  record.count++;
  if (record.count > RATE_LIMIT_MAX_REQUESTS) {
    return false;
  }

  return true;
}

function getCORSHeaders(origin) {
  if (ALLOWED_ORIGINS.includes(origin)) {
    return {
      'Access-Control-Allow-Origin': origin,
      'Access-Control-Allow-Methods': 'GET, POST, PUT, DELETE, OPTIONS',
      'Access-Control-Allow-Headers': 'Content-Type, Authorization, X-Request-ID',
      'Access-Control-Max-Age': '86400',
      'Vary': 'Origin',
    };
  }
  return {};
}

function generateRequestId() {
  return crypto.randomUUID();
}

function sanitizeInput(str) {
  if (typeof str !== 'string') return str;
  return str.replace(/[<>]/g, '').trim();
}

function createSecureHeaders(additionalHeaders = {}) {
  return {
    'Content-Type': 'application/json',
    'X-Content-Type-Options': 'nosniff',
    'X-Frame-Options': 'DENY',
    'Strict-Transport-Security': 'max-age=31536000; includeSubDomains',
    'Cache-Control': 'no-store',
    'Referrer-Policy': 'strict-origin-when-cross-origin',
    ...additionalHeaders,
  };
}

function jsonResponse(data, status = 200, additionalHeaders = {}) {
  return new Response(JSON.stringify(data), {
    status,
    headers: createSecureHeaders(additionalHeaders),
  });
}

function errorResponse(message, status, requestId) {
  return jsonResponse(
    {
      error: message,
      requestId,
      timestamp: new Date().toISOString(),
    },
    status
  );
}

async function forwardToService(service, request, requestId, path, env) {
  const url = new URL(request.url);
  url.pathname = path;

  const headers = new Headers(request.headers);
  headers.set('X-Request-ID', requestId);
  headers.set('X-Forwarded-For', request.headers.get('CF-Connecting-IP') || 'unknown');
  headers.set('X-Internal-Secret', env.INTERNAL_SECRET || '');
  headers.delete('Cookie');

  const serviceRequest = new Request(url.toString(), {
    method: request.method,
    headers,
    body: request.method !== 'GET' && request.method !== 'HEAD' ? request.body : null,
  });

  try {
    const response = await service.fetch(serviceRequest);
    const responseHeaders = new Headers(response.headers);
    responseHeaders.set('X-Request-ID', requestId);

    return new Response(response.body, {
      status: response.status,
      headers: createSecureHeaders(Object.fromEntries(responseHeaders)),
    });
  } catch (err) {
    console.error(`Service binding error [${requestId}]:`, err.message);
    return errorResponse('Service temporarily unavailable', 503, requestId);
  }
}

const routeMap = [
  { prefix: '/api/v1/auth', serviceKey: 'AUTH_SERVICE' },
  { prefix: '/api/v1/users', serviceKey: 'USER_SERVICE' },
  { prefix: '/api/v1/data', serviceKey: 'DATA_SERVICE' },
  { prefix: '/api/v1/notifications', serviceKey: 'NOTIFICATION_SERVICE' },
];

export default {
  async fetch(request, env, ctx) {
    const requestId = generateRequestId();
    const origin = request.headers.get('Origin') || '';
    const corsHeaders = getCORSHeaders(origin);

    if (request.method === 'OPTIONS') {
      return new Response(null, {
        status: 204,
        headers: { ...corsHeaders },
      });
    }

    const clientIP = request.headers.get('CF-Connecting-IP') || 'unknown';
    if (!checkRateLimit(clientIP)) {
      return errorResponse('Rate limit exceeded', 429, requestId);
    }

    const url = new URL(request.url);
    const path = url.pathname;

    if (path === '/health') {
      return jsonResponse({ status: 'healthy', requestId }, 200, corsHeaders);
    }

    for (const route of routeMap) {
      if (path.startsWith(route.prefix)) {
        const service = env[route.serviceKey];
        if (!service) {
          return errorResponse('Service not configured', 500, requestId);
        }
        const internalPath = path.substring(route.prefix.length) || '/';
        const response = await forwardToService(service, request, requestId, internalPath, env);

        const finalHeaders = new Headers(response.headers);
        for (const [key, value] of Object.entries(corsHeaders)) {
          finalHeaders.set(key, value);
        }

        return new Response(response.body, {
          status: response.status,
          headers: finalHeaders,
        });
      }
    }

    return errorResponse('Not found', 404, requestId);
  },
};